# --- App Setup ---
app = Flask(__name__)
app.config["SECRET_KEY"] = os.environ.get("SECRET_KEY", "change-this-in-production")

# --- In-memory user store (replace with a real database) ---
users_db = {}
sessions_db = {}

# --- Rate limiting (simple in-memory) ---
login_attempts = {}
MAX_ATTEMPTS = 5
LOCKOUT_DURATION = timedelta(minutes=15)


def _mask_email(email):
    """Mask email for safe logging: john@example.com -> j***@example.com"""
    if not email or "@" not in email:
        return "***"
    local, domain = email.split("@", 1)
    if len(local) <= 1:
        masked_local = "*"
    else:
        masked_local = local[0] + "***"
    return f"{masked_local}@{domain}"


def _mask_username(username):
    """Mask username for safe logging: johndoe -> jo***oe"""
    if not username:
        return "***"
    if len(username) <= 2:
        return username[0] + "***"
    return username[:2] + "***" + username[-2:]


def _get_client_ip():
    """Get client IP, considering proxies."""
    if request.headers.get("X-Forwarded-For"):
        return request.headers.get("X-Forwarded-For").split(",")[0].strip()
    return request.remote_addr


def _generate_request_id():
    """Generate a unique request ID for correlating log entries."""
    return str(uuid.uuid4())[:8]


def _is_rate_limited(username):
    """Check if a user is rate-limited due to too many failed attempts."""
    key = username.lower()
    if key in login_attempts:
        attempts, lockout_time = login_attempts[key]
        if lockout_time and datetime.utcnow() < lockout_time:
            return True
        if lockout_time and datetime.utcnow() >= lockout_time:
            del login_attempts[key]
            return False
    return False


def _record_failed_attempt(username):
    """Record a failed login attempt for rate limiting."""
    key = username.lower()
    if key in login_attempts:
        attempts, _ = login_attempts[key]
        attempts += 1
    else:
        attempts = 1

    lockout_time = None
    if attempts >= MAX_ATTEMPTS:
        lockout_time = datetime.utcnow() + LOCKOUT_DURATION

    login_attempts[key] = (attempts, lockout_time)
    return attempts


def _clear_failed_attempts(username):
    """Clear failed attempts after successful login."""
    key = username.lower()
    if key in login_attempts:
        del login_attempts[key]


def _log_auth_event(event_type, username, email=None, success=False, reason=None, request_id=None):
    """
    Securely log authentication events.
    NEVER logs passwords, tokens, or other secrets.
    """
    log_data = {
        "request_id": request_id,
        "event": event_type,
        "username": _mask_username(username),
        "email": _mask_email(email) if email else "N/A",
        "ip_address": _get_client_ip(),
        "user_agent": request.headers.get("User-Agent", "Unknown"),
        "success": success,
        "reason": reason or "N/A",
        "timestamp": datetime.utcnow().isoformat(),
    }

    log_message = (
        f"AUTH_EVENT | request_id={log_data['request_id']} | "
        f"event={log_data['event']} | "
        f"username={log_data['username']} | "
        f"email={log_data['email']} | "
        f"ip={log_data['ip_address']} | "
        f"user_agent={log_data['user_agent']} | "
        f"success={log_data['success']} | "
        f"reason={log_data['reason']}"
    )

    if success:
        logger.info(log_message)
    else:
        logger.warning(log_message)


def require_auth(f):
    """Decorator to require authentication via session token."""
    @wraps(f)
    def decorated(*args, **kwargs):
        token = request.headers.get("Authorization", "").replace("Bearer ", "")
        if not token or token not in sessions_db:
            return jsonify({"error": "Authentication required"}), 401
        request.current_user = sessions_db[token]
        return f(*args, **kwargs)
    return decorated


