@app.route("/api/register", methods=["POST"])
def register():
    """Register a new user."""
    request_id = _generate_request_id()
    data = request.get_json()

    if not data:
        return jsonify({"error": "Request body is required"}), 400

    username = data.get("username", "").strip()
    password = data.get("password", "")
    email = data.get("email", "").strip()

    # Validation
    if not username or not password or not email:
        _log_auth_event(
            "REGISTER", username, email,
            success=False, reason="Missing required fields",
            request_id=request_id
        )
        return jsonify({"error": "Username, password, and email are required"}), 400

    if len(password) < 8:
        _log_auth_event(
            "REGISTER", username, email,
            success=False, reason="Password too short",
            request_id=request_id
        )
        return jsonify({"error": "Password must be at least 8 characters"}), 400

    if username.lower() in users_db:
        _log_auth_event(
            "REGISTER", username, email,
            success=False, reason="Username already exists",
            request_id=request_id
        )
        return jsonify({"error": "Username already exists"}), 409

    # Store user (password is hashed, NEVER stored in plain text)
    users_db[username.lower()] = {
        "username": username,
        "email": email,
        "password_hash": generate_password_hash(password),
        "created_at": datetime.utcnow().isoformat(),
    }

    _log_auth_event(
        "REGISTER", username, email,
        success=True, reason="User registered successfully",
        request_id=request_id
    )

    return jsonify({
        "message": "User registered successfully",
        "request_id": request_id
    }), 201


@app.route("/api/login", methods=["POST"])
def login():
    """Authenticate a user and return a session token."""
    request_id = _generate_request_id()
    data = request.get_json()

    if not data:
        return jsonify({"error": "Request body is required"}), 400

    username = data.get("username", "").strip()
    password = data.get("password", "")

    if not username or not password:
        _log_auth_event(
            "LOGIN", username or "EMPTY",
            success=False, reason="Missing credentials",
            request_id=request_id
        )
        return jsonify({"error": "Username and password are required"}), 400

    # Rate limiting check
    if _is_rate_limited(username):
        _log_auth_event(
            "LOGIN", username,
            success=False, reason="Account temporarily locked (rate limit)",
            request_id=request_id
        )
        logger.warning(
            f"RATE_LIMIT | request_id={request_id} | "
            f"username={_mask_username(username)} | "
            f"ip={_get_client_ip()} | Account locked due to too many failed attempts"
        )
        return jsonify({
            "error": "Account temporarily locked due to too many failed attempts. Try again later.",
            "request_id": request_id
        }), 429

    # Look up user
    user = users_db.get(username.lower())

    if not user:
        _record_failed_attempt(username)
        _log_auth_event(
            "LOGIN", username,
            success=False, reason="User not found",
            request_id=request_id
        )
        # Return generic message to prevent username enumeration
        return jsonify({
            "error": "Invalid username or password",
            "request_id": request_id
        }), 401

    # Verify password
    if not check_password_hash(user["password_hash"], password):
        attempt_count = _record_failed_attempt(username)
        _log_auth_event(
            "LOGIN", username, user.get("email"),
            success=False,
            reason=f"Invalid password (attempt {attempt_count}/{MAX_ATTEMPTS})",
            request_id=request_id
        )
        return jsonify({
            "error": "Invalid username or password",
            "request_id": request_id
        }), 401

    # Successful login
    _clear_failed_attempts(username)

    session_token = str(uuid.uuid4())
    sessions_db[session_token] = {
        "username": user["username"],
        "email": user["email"],
        "login_time": datetime.utcnow().isoformat(),
        "ip_address": _get_client_ip(),
    }

    _log_auth_event(
        "LOGIN", username, user.get("email"),
        success=True, reason="Login successful",
        request_id=request_id
    )

    return jsonify({
        "message": "Login successful",
        "token": session_token,
        "username": user["username"],
        "request_id": request_id
    }), 200


@app.route("/api/logout", methods=["POST"])
@require_auth
def logout():
    """Log out the current user."""
    request_id = _generate_request_id()
    token = request.headers.get("Authorization", "").replace("Bearer ", "")
    user_info = sessions_db.pop(token, None)

    if user_info:
        _log_auth_event(
            "LOGOUT", user_info["username"], user_info.get("email"),
            success=True, reason="User logged out",
            request_id=request_id
        )

    return jsonify({
        "message": "Logged out successfully",
        "request_id": request_id
    }), 200


